import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../api/client';
import AppNavbar from '../../components/AppNavbar';
import ClosedTickets from '../../components/ClosedTickets';

export default function DeveloperDashboard() {
  const navigate = useNavigate();

  // Filters
  const [ticketIdSearch, setTicketIdSearch] = useState('');
  const [departmentFilter, setDepartmentFilter] = useState('');
  const [divisionSearch, setDivisionSearch] = useState('');
  const [moduleFilter, setModuleFilter] = useState('');
  const [submoduleFilter, setSubmoduleFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [departments, setDepartments] = useState([]);
const [modules, setModules] = useState([]);
const [submodules, setSubmodules] = useState([]);

const [createdFromDate, setCreatedFromDate] = useState('');
const [createdToDate, setCreatedToDate] = useState('');

const [closedFromDate, setClosedFromDate] = useState('');
const [closedToDate, setClosedToDate] = useState('');

const [bugTypeSearch, setBugTypeSearch] = useState('');

  // Data
  const [tickets, setTickets] = useState([]);
  const [summary, setSummary] = useState({
    total: 0,
    open: 0,
    reopened: 0,
    closed: 0,
  });

  const filteredModules =
  !departmentFilter
    ? modules
    : modules.filter(
        (module) =>
          Number(
            module.department ||
            module.department_id
          ) ===
          Number(departmentFilter)
      );

const filteredSubmodules =
  !moduleFilter
    ? submodules
    : submodules.filter(
        (submodule) =>
          Number(
            submodule.module
          ) ===
          Number(moduleFilter)
      );

  // Pagination
  const [page, setPage] = useState(1);
  const [count, setCount] = useState(0);
  const [nextPage, setNextPage] = useState(null);
  const [previousPage, setPreviousPage] = useState(null);

  const [error, setError] = useState('');

  const loadDropdowns = async () => {
  try {
    const [
      deptRes,
      moduleRes,
      submoduleRes,
    ] = await Promise.all([
      api.get('/masters/departments/'),
      api.get('/masters/modules/'),
      api.get('/masters/submodules/'),
    ]);

    setDepartments(
      deptRes.data.results ||
      deptRes.data ||
      []
    );

    setModules(
      moduleRes.data.results ||
      moduleRes.data ||
      []
    );

    setSubmodules(
      submoduleRes.data.results ||
      submoduleRes.data ||
      []
    );
  } catch (err) {
    console.error(err);
  }
};

  // Load Summary
  const loadSummary = async () => {
    try {
      const res = await api.get('/dashboard/summary/');

      setSummary({
        total: res.data.total || 0,
        open: res.data.open || 0,
        reopened: res.data.reopened || 0,
        closed: res.data.closed || 0,
      });
    } catch (err) {
      console.error('Failed to load summary', err);
    }
  };

  // Load Tickets
  const loadTickets = async (pageNo = page) => {
    try {
      const res = await api.get('/tickets/', {
        params: {
          page: pageNo,
          is_sent_to_developer: true,
        },
      });

      setTickets(res.data.results || []);
      setCount(res.data.count || 0);
      setNextPage(res.data.next);
      setPreviousPage(res.data.previous);
      setError('');
    } catch (err) {
      console.error(err);
      setError('Failed to load developer tickets');
      setTickets([]);
    }
  };

  useEffect(() => {
    loadSummary();
    loadDropdowns();
  }, []);

  useEffect(() => {
    loadTickets(page);
  }, [page]);

  // Update Ticket
  const handleUpdate = async (ticketId, status, developerRemark) => {
    try {
      await api.post(`/tickets/${ticketId}/developer_update/`, {
        status,
        developer_remark: developerRemark,
      });

      loadSummary();
      loadTickets(page);
    } catch (err) {
      console.error(err);
      alert('Failed to update ticket');
    }
  };

  // View Ticket
  const handleView = (ticketId) => {
    navigate(`/developer/ticket/${ticketId}`);
  };

  // Pagination
  const totalPages = Math.ceil(count / 8);

  // Filtered Tickets
  const filteredTickets = tickets.filter((ticket) => {
    return (
      ticket.ticket_id
        ?.toString()
        .toLowerCase()
        .includes(ticketIdSearch.toLowerCase()) &&

      (departmentFilter === '' ||
        ticket.department_name === departmentFilter) &&

      ticket.division_name
        ?.toLowerCase()
        .includes(divisionSearch.toLowerCase()) &&

      (moduleFilter === '' ||
        ticket.module_name === moduleFilter) &&

      (submoduleFilter === '' ||
        ticket.submodule_name === submoduleFilter) &&

      (statusFilter === '' ||
        ticket.status === statusFilter) &&

      ticket.bug_type
        ?.toLowerCase()
        .includes(bugTypeSearch.toLowerCase())
    );
  });

  return (
    <>
      <AppNavbar />

      <div className="container mt-4">
        <h2 className="mb-4">Developer Dashboard</h2>

        {error && (
          <div className="alert alert-danger">
            {error}
          </div>
        )}

        {/* Summary Cards */}
        <div className="row mb-4">

          <div className="col-md-3 mb-3">
            <div className="card">
              <div className="card-body">
                <h5>Total Tickets</h5>
                <h2>{summary.total}</h2>
              </div>
            </div>
          </div>

          <div className="col-md-3 mb-3">
            <div className="card">
              <div className="card-body">
                <h5>Open Tickets</h5>
                <h2>{summary.open}</h2>
              </div>
            </div>
          </div>

          <div className="col-md-3 mb-3">
            <div className="card">
              <div className="card-body">
                <h5>Reopened</h5>
                <h2>{summary.reopened}</h2>
              </div>
            </div>
          </div>

          <div className="col-md-3 mb-3">
            <div className="card">
              <div className="card-body">
                <h5>Closed</h5>
                <h2>{summary.closed}</h2>
              </div>
            </div>
          </div>

        </div>

        {/* Ticket Table */}
        <div className="card mb-4">
          <div className="card-body">

            <h4 className="mb-3">
              Tickets Sent to Development
            </h4>

            {/* Filters */}
            <div className="row g-2 mb-3">

              {/* Ticket ID */}
              <div className="col-md-2">
                <input
                  type="text"
                  className="form-control"
                  placeholder="Ticket ID"
                  value={ticketIdSearch}
                  onChange={(e) =>
                    setTicketIdSearch(e.target.value)
                  }
                />
              </div>

              {/* Department */}
              <div className="col-md-2">
                <select
                  className="form-select"
                  value={departmentFilter}
                  onChange={(e) =>
                    setDepartmentFilter(e.target.value)
                  }
                >
                  <option value="">
                    All Departments
                  </option>

                  {[...new Set(
                    tickets.map(
                      (t) => t.department_name
                    )
                  )]
                    .filter(Boolean)
                    .map((dept, index) => (
                      <option
                        key={index}
                        value={dept}
                      >
                        {dept}
                      </option>
                    ))}
                </select>
              </div>

              {/* Division */}
              <div className="col-md-2">
                <input
                  type="text"
                  className="form-control"
                  placeholder="Division"
                  value={divisionSearch}
                  onChange={(e) =>
                    setDivisionSearch(e.target.value)
                  }
                />
              </div>

              {/* Module */}
              <div className="col-md-2">
                <select
                  className="form-select"
                  value={moduleFilter}
                  onChange={(e) =>
                    setModuleFilter(e.target.value)
                  }
                >
                  <option value="">
                    All Modules
                  </option>

                  {[...new Set(
                    tickets.map(
                      (t) => t.module_name
                    )
                  )]
                    .filter(Boolean)
                    .map((module, index) => (
                      <option
                        key={index}
                        value={module}
                      >
                        {module}
                      </option>
                    ))}
                </select>
              </div>

              {/* Submodule */}
              <div className="col-md-2">
                <select
                  className="form-select"
                  value={submoduleFilter}
                  onChange={(e) =>
                    setSubmoduleFilter(e.target.value)
                  }
                >
                  <option value="">
                    All Submodules
                  </option>

                  {[...new Set(
                    tickets.map(
                      (t) => t.submodule_name
                    )
                  )]
                    .filter(Boolean)
                    .map((sub, index) => (
                      <option
                        key={index}
                        value={sub}
                      >
                        {sub}
                      </option>
                    ))}
                </select>
              </div>

              {/* Status */}
              <div className="col-md-2">
                <select
                  className="form-select"
                  value={statusFilter}
                  onChange={(e) =>
                    setStatusFilter(e.target.value)
                  }
                >
                  <option value="">
                    All Status
                  </option>

                  <option value="Sent to Developer">
                    Sent to Developer
                  </option>

                  <option value="Developer In Progress">
                    Developer In Progress
                  </option>

                  <option value="Reopened">
                    Reopened
                  </option>

                  <option value="Closed">
                    Closed
                  </option>
                </select>
              </div>

              {/* Bug Type */}
              <div className="col-md-2">
                <input
                  type="text"
                  className="form-control"
                  placeholder="Bug Type"
                  value={bugTypeSearch}
                  onChange={(e) =>
                    setBugTypeSearch(e.target.value)
                  }
                />
              </div>

            </div>

            {/* Table */}
            <div className="table-responsive">

              <table className="table table-bordered table-striped">

                <thead>
                  <tr>
                    <th>Ticket ID</th>
                    <th>Department</th>
                    <th>Division</th>
                    <th>Module</th>
                    <th>Submodule</th>
                    <th>Bug Type</th>
                    <th>Subject</th>
                    <th>Created Date</th>
                    <th>Status</th>
                    <th>Support Remark</th>
                    <th>View</th>
                    <th>Developer Remark</th>
                    <th>Closed Date</th>
                    <th>Update</th>
                  </tr>
                </thead>

                <tbody>

                  {filteredTickets.length > 0 ? (
                    filteredTickets.map((ticket) => (

                      <tr key={ticket.id}>

                        <td>{ticket.ticket_id}</td>

                        <td>
                          {ticket.department_name || ''}
                        </td>

                        <td>
                          {ticket.division_name || ''}
                        </td>

                        <td>
                          {ticket.module_name || ''}
                        </td>

                        <td>
                          {ticket.submodule_name || ''}
                        </td>

                        <td>
                          {ticket.bug_type || ''}
                        </td>

                        <td>{ticket.subject}</td>

                        <td>
                          {ticket.created_at
                            ? new Date(
                                ticket.created_at
                              ).toLocaleString()
                            : ''}
                        </td>

                        <td>{ticket.status}</td>

                        <td>
                          {ticket.support_remark || ''}
                        </td>

                        {/* View */}
                        <td>
                          <button
                            className="btn btn-outline-primary btn-sm"
                            onClick={() =>
                              handleView(ticket.id)
                            }
                          >
                            👁
                          </button>
                        </td>

                        {/* Developer Remark */}
                        <td>
                          <textarea
                            className="form-control"
                            rows="2"
                            defaultValue={
                              ticket.developer_remark || ''
                            }
                            id={`remark-${ticket.id}`}
                          />
                        </td>

                        {/* Closed Date */}
                        <td>
                          {ticket.closed_at
                            ? new Date(
                                ticket.closed_at
                              ).toLocaleString()
                            : ''}
                        </td>

                        {/* Update */}
                        <td>

                          <select
                            className="form-select mb-2"
                            defaultValue={ticket.status}
                            id={`status-${ticket.id}`}
                          >
                            <option value="Sent to Developer">
                              Sent to Developer
                            </option>

                            <option value="Developer In Progress">
                              Developer In Progress
                            </option>

                            <option value="Reopened">
                              Reopened
                            </option>

                            <option value="Closed">
                              Closed
                            </option>

                          </select>

                          <button
                            className="btn btn-primary btn-sm"
                            onClick={() =>
                              handleUpdate(
                                ticket.id,
                                document.getElementById(
                                  `status-${ticket.id}`
                                ).value,
                                document.getElementById(
                                  `remark-${ticket.id}`
                                ).value
                              )
                            }
                          >
                            Update
                          </button>

                        </td>

                      </tr>

                    ))
                  ) : (
                    <tr>
                      <td colSpan="14">
                        No matching tickets found
                      </td>
                    </tr>
                  )}

                </tbody>

              </table>

            </div>

            {/* Pagination */}
            <div className="d-flex justify-content-between align-items-center mt-3">

              <div>
                Total Tickets:{' '}
                <strong>{count}</strong>
              </div>

              <div className="d-flex align-items-center gap-2">

                <button
                  className="btn btn-outline-secondary"
                  disabled={!previousPage}
                  onClick={() =>
                    setPage((prev) => prev - 1)
                  }
                >
                  Previous
                </button>

                <span>
                  Page <strong>{page}</strong> of{' '}
                  <strong>{totalPages || 1}</strong>
                </span>

                <button
                  className="btn btn-outline-secondary"
                  disabled={!nextPage}
                  onClick={() =>
                    setPage((prev) => prev + 1)
                  }
                >
                  Next
                </button>

              </div>

            </div>

          </div>
        </div>

        <ClosedTickets />

      </div>
    </>
  );
}
